code.C:
#include <stdio.h>

int main() {
    int numbers[5];
    int sum = 0;

    // Input: Enter 5 integers
    for (int i = 0; i < 5; i++) {
        scanf("%d", &numbers[i]);
    }

    // Calculate the sum of array elements
    for (int i = 0; i < 5; i++) {
        sum += numbers[i];
    }

    // Output: Print the sum
    printf("%d\n", sum);

    return 0;
}

